{"code":"import json, pandas as pd

def load_any(x):
    if isinstance(x, str):
        with open(x, 'r', encoding='utf-8') as f:
            return json.load(f)
    return x

recs = load_any(var_call_HiQ0VIm9gGh3sTcqhfz8QZAt)

df = pd.DataFrame(recs)
# parse author name if json

def author_name(a):
    if a is None:
        return None
    if isinstance(a, str):
        s = a.strip()
        if s == 'None':
            return None
        if s.startswith('{') and '"name"' in s:
            try:
                return json.loads(s).get('name')
            except Exception:
                return s
        return s
    return str(a)

df['author_name'] = df['author'].apply(author_name)

df2 = df[['title','author_name','avg_rating','review_count','book_id']].sort_values(['title','book_id'])
lines = []
for _, r in df2.iterrows():
    title = r['title']
    author = r['author_name'] if pd.notna(r['author_name']) and r['author_name']!='' else 'Unknown'
    lines.append(f"{title} — {author} (avg rating 5.0; {int(r['review_count'])} reviews)")
answer = "\n".join(lines)
print('__RESULT__:')
print(json.dumps(answer, ensure_ascii=False))"}

